PASSO 1: Criar o "Painel de Avisos" (Dashboard de Revisões)
Vamos criar o componente visual que listará as revisões de "Hoje" e as "Atrasadas", isolando essa lógica para não criar um arquivo monolítico gigante.

Crie um NOVO arquivo em: src/components/student/courses/reviews/CourseReviewDashboard.tsx
import React, { useEffect, useState } from 'react';
import { courseReviewService, CourseReview } from '../../../../services/courseReviewService';
import { useAuth } from '../../../../contexts/AuthContext';
import { AlertCircle, CalendarClock, CheckCircle2, ChevronRight } from 'lucide-react';

export function CourseReviewDashboard({ courseId, onReviewNow }: { courseId: string, onReviewNow: (topicId: string) => void }) {
    const { user } = useAuth();
    const [reviews, setReviews] = useState<CourseReview[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchReviews = async () => {
        if (!user) return;
        try {
            const data = await courseReviewService.getPendingReviews(user.uid, courseId);
            setReviews(data);
        } catch (error) {
            console.error("Erro ao buscar revisões:", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReviews();
    }, [courseId, user]);

    const handleComplete = async (review: CourseReview) => {
        if (!user) return;
        // Atualização Otimista: Some da tela na hora em que clica
        setReviews(prev => prev.filter(r => r.id !== review.id));
        try {
            await courseReviewService.completeReview(user.uid, review);
        } catch (error) {
            console.error("Erro ao concluir revisão:", error);
            fetchReviews(); // Reverte caso dê erro no banco
        }
    };

    if (loading || reviews.length === 0) return null;

    // Garante a formatação da data baseada no fuso horário local do usuário (YYYY-MM-DD)
    const getLocalDateStr = () => {
        const d = new Date();
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    };
    const todayStr = getLocalDateStr();

    const overdueReviews = reviews.filter(r => r.scheduledDate < todayStr);
    const todayReviews = reviews.filter(r => r.scheduledDate === todayStr);

    if (overdueReviews.length === 0 && todayReviews.length === 0) return null;

    return (
        <div className="flex flex-col gap-3 mb-6 animate-in fade-in slide-in-from-top-4">
            {overdueReviews.length > 0 && (
                <div className="bg-red-900/10 border border-red-900/50 rounded-xl p-4 shadow-lg shadow-red-900/5">
                    <div className="flex items-center gap-2 mb-3">
                        <AlertCircle size={18} className="text-red-500" />
                        <h3 className="text-red-500 font-black uppercase text-sm">Revisões Atrasadas</h3>
                    </div>
                    <div className="flex flex-col gap-2">
                        {overdueReviews.map(review => (
                            <ReviewCard key={review.id} review={review} onReviewNow={onReviewNow} onComplete={handleComplete} isOverdue={true} />
                        ))}
                    </div>
                </div>
            )}

            {todayReviews.length > 0 && (
                <div className="bg-yellow-900/10 border border-yellow-900/50 rounded-xl p-4 shadow-lg shadow-yellow-900/5">
                    <div className="flex items-center gap-2 mb-3">
                        <CalendarClock size={18} className="text-yellow-500" />
                        <h3 className="text-yellow-500 font-black uppercase text-sm">Você possui revisões agendadas para hoje:</h3>
                    </div>
                    <div className="flex flex-col gap-2">
                        {todayReviews.map(review => (
                            <ReviewCard key={review.id} review={review} onReviewNow={onReviewNow} onComplete={handleComplete} isOverdue={false} />
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

// Subcomponente de Card Isolado
function ReviewCard({ review, onReviewNow, onComplete, isOverdue }: { review: CourseReview, onReviewNow: (id: string) => void, onComplete: (r: CourseReview) => void, isOverdue: boolean }) {
    return (
        <div className="flex flex-col sm:flex-row sm:items-center justify-between bg-[#121418] border border-gray-800 rounded-lg p-3 gap-4 hover:border-gray-700 transition-colors">
            <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase ${isOverdue ? 'bg-red-500/20 text-red-400' : 'bg-yellow-500/20 text-yellow-500'}`}>
                        {review.label}
                    </span>
                    <span className="text-[10px] text-gray-500 font-bold uppercase">{review.disciplineName}</span>
                </div>
                <p className="text-sm font-bold text-white">{review.topicName}</p>
            </div>
            <div className="flex items-center gap-2">
                <button onClick={() => onComplete(review)} className="flex items-center gap-2 px-3 py-1.5 bg-transparent hover:bg-green-900/20 text-green-500 border border-green-900/50 rounded text-xs font-bold uppercase transition-colors">
                    <CheckCircle2 size={14} /> Concluir Revisão
                </button>
                <button onClick={() => onReviewNow(review.topicId)} className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white rounded text-xs font-bold uppercase transition-colors shadow-md shadow-blue-900/20">
                    Revisar Agora <ChevronRight size={14} />
                </button>
            </div>
        </div>
    );
}

