export function StudentCourseEdital({ courseId, initialFocusTopicId }: { courseId: string, initialFocusTopicId?: string | null }) {
    const { currentUser: user } = useAuth();
    const [structure, setStructure] = useState<CourseEditalStructure | null>(null);
    const [loading, setLoading] = useState(true);
    const [completedTopics, setCompletedTopics] = useState<string[]>([]);

    // Novas vars
    const [completedLessons, setCompletedLessons] = useState<string[]>([]);

    useEffect(() => {
        const loadData = async () => {
            if (!user) return;
            setLoading(true);
            try {
                const [editalData, topicsDone, lessonsDone] = await Promise.all([
                    courseService.getCourseEdital(courseId),
                    courseService.getCompletedTopics(user.uid, courseId),
                    courseService.getCompletedLessons(user.uid, courseId)
                ]);
                setStructure(editalData);
                // Garante que todos os IDs de tópicos sejam strings
                setCompletedTopics((topicsDone || []).map(String));
                setCompletedLessons(lessonsDone || []);
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        loadData();
    }, [courseId, user]);

    // Função Blindada para Marcar/Desmarcar o Tópico (Optimistic UI)
    const handleToggleTopic = (topicId: string | number) => {
        if (!user) return;
        const safeId = String(topicId);

        // setCompletedTopics com 'prev' garante que NUNCA usaremos dados obsoletos
        setCompletedTopics(prev => {
            const isAlreadyCompleted = prev.includes(safeId);
            const newStatus = !isAlreadyCompleted;

            // 1. Dispara o salvamento pro banco em segundo plano (não trava a tela)
            courseService.toggleTopicCompletion(user.uid, courseId, safeId, newStatus)
                .catch(err => console.error("Erro ao salvar progresso no banco:", err));

            // 2. Atualiza a interface instantaneamente (o Check fica verde na mesma hora)
            if (newStatus) {
                return [...prev, safeId];
            } else {
                return prev.filter(id => String(id) !== safeId);
            }
        });
    };

    if (loading) return <div className="flex justify-center p-20"><Loader2 className="animate-spin text-red-500" /></div>;

    if (!structure || !structure.disciplines || structure.disciplines.length === 0) {
        return (
            <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl">
                <BookOpen className="w-12 h-12 text-gray-600 mx-auto mb-4" />
                <p className="text-gray-500 uppercase font-bold text-sm">Edital não disponível.</p>
                <p className="text-gray-600 text-xs mt-1">O professor ainda não publicou o edital verticalizado.</p>
            </div>
        );
    }

    // --- CÁLCULO DA BARRA DE PROGRESSO GERAL ---
    const countTotalTopics = (items: any[]): number => {
        let count = 0;
        items.forEach(item => {
            count++; 
            if (item.subtopics && item.subtopics.length > 0) {
                count += countTotalTopics(item.subtopics); 
            }
        });
        return count;
    };

    const totalTopics = structure.disciplines.reduce((acc: number, disc: any) => acc + countTotalTopics(disc.topics || []), 0);
    const overallProgress = totalTopics > 0 ? Math.round((completedTopics.length / totalTopics) * 100) : 0;

    return (
        <div className="space-y-6 pb-20 animate-in fade-in">
            {/* Header / Resumo */}
            <div className="flex flex-col md:flex-row justify-between items-end gap-4 border-b border-gray-800 pb-6">
                <div>
                    <h2 className="text-2xl font-black text-white uppercase tracking-tighter">Edital Verticalizado</h2>
                    <p className="text-gray-500 text-sm font-medium mt-1">Acompanhe seu progresso tópico por tópico.</p>
                </div>

                {/* BARRA DE PROGRESSO GERAL */}
                <div className="bg-[#1a1d24] border border-gray-800 rounded-xl p-3 flex flex-col gap-1 w-full md:w-64">
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wider block">Progresso Geral</span>
                        <span className="text-sm font-black text-white">{overallProgress}%</span>
                    </div>
                    <div className="w-full bg-black rounded-full h-2 overflow-hidden border border-gray-800">
                        <div className="bg-green-500 h-full rounded-full transition-all duration-700 ease-out" style={{ width: `${overallProgress}%` }}></div>
                    </div>
                </div>
            </div>

            {/* Lista de Disciplinas */}
            <div className="space-y-4">
                {structure.disciplines.map(discipline => (
                    <StudentDisciplineAccordion 
                        key={discipline.id} 
                        discipline={discipline} 
                        courseId={courseId}
                        completedLessons={completedLessons}
                        completedTopics={completedTopics} 
                        onToggleTopic={handleToggleTopic}
                        focusTopicId={initialFocusTopicId} // PASSANDO O ID DE FOCO PARA BAIXO
                    />
                ))}
            </div>
        </div>
    );
}

import { 
  collection, 
  doc, 
  writeBatch, 
  getDocs, 
  query, 
  where, 
  updateDoc, 
  Timestamp, 
  addDoc
} from 'firebase/firestore';
import { db } from './firebase';
import { getLocalISODate } from './scheduleService';

export interface CourseReview {
  id: string;
  userId: string;
  courseId: string;
  disciplineId: string;
  disciplineName: string; // Novo campo
  topicId: string;
  topicName: string;
  scheduledDate: string; // Formato YYYY-MM-DD
  status: 'pending' | 'completed' | 'missed';
  reviewIndex: number;
  intervalDays: number;
  label: string;
  isLastOfCycle: boolean;
  repeatInterval: number | null;
  createdAt: any; // Timestamp
  completedAt?: any; // Timestamp
}

export const courseReviewService = {
  /**
   * 1. Agenda as revisões com base nos intervalos
   * Calcula as datas de forma cumulativa (Data Rev 2 = Data Rev 1 + Intervalo 2)
   */
  scheduleReviews: async (
    userId: string, 
    courseId: string, 
    disciplineId: string, 
    disciplineName: string, // Novo parâmetro
    topicId: string, 
    topicName: string, 
    intervals: number[], 
    repeatLast: boolean
  ) => {
    const batch = writeBatch(db);
    const reviewsRef = collection(db, 'users', userId, 'course_reviews');

    // Começa a contar a partir de "Hoje"
    let currentDateCalculation = new Date();

    intervals.forEach((interval, index) => {
      // Lógica de Acumulação: A próxima revisão é X dias APÓS a anterior
      currentDateCalculation.setDate(currentDateCalculation.getDate() + interval);

      // Usa helper para garantir string YYYY-MM-DD correta no fuso local
      const scheduledDateStr = getLocalISODate(currentDateCalculation);

      const isLast = index === intervals.length - 1;
      const newReviewRef = doc(reviewsRef); // Gera ID automaticamente

      const reviewData: CourseReview = {
        id: newReviewRef.id,
        userId,
        courseId,
        disciplineId,
        disciplineName,
        topicId,
        topicName,
        scheduledDate: scheduledDateStr,
        status: 'pending',
        reviewIndex: index + 1,
        intervalDays: interval,
        label: `REV. ${index + 1} - ${interval} DIA${interval > 1 ? 'S' : ''}`,
        isLastOfCycle: isLast,
        repeatInterval: isLast && repeatLast ? interval : null,
        createdAt: Timestamp.now()
      };

      batch.set(newReviewRef, reviewData);
    });

    await batch.commit();
  },

  /**
   * 2. Busca revisões pendentes ou atrasadas de um curso específico
   */
  getPendingReviews: async (userId: string, courseId: string) => {
    const reviewsRef = collection(db, 'users', userId, 'course_reviews');

    // Busca tudo que não está concluído para este curso
    const q = query(
        reviewsRef, 
        where('courseId', '==', courseId), 
        where('status', '!=', 'completed')
    );

    const snapshot = await getDocs(q);

    const reviews = snapshot.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data() 
    } as CourseReview));

    // Ordena pela data mais antiga primeiro (Client-side sort para evitar índice complexo composto)
    return reviews.sort((a, b) => a.scheduledDate.localeCompare(b.scheduledDate));
  },

  /**
   * 3. Busca revisões específicas de um Tópico (Para exibir no Edital)
   */
  getReviewsByTopic: async (userId: string, topicId: string) => {
    const reviewsRef = collection(db, 'users', userId, 'course_reviews');

    const q = query(
        reviewsRef, 
        where('topicId', '==', topicId)
    );

    const snapshot = await getDocs(q);

    const reviews = snapshot.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data() 
    } as CourseReview));

    // Ordena pelo índice da revisão (REV 1, REV 2...)
    return reviews.sort((a, b) => a.reviewIndex - b.reviewIndex);
  },

  /**
   * 4. Deleta todas as revisões de um tópico (Quando o aluno desmarca conclusão)
   */
  deleteReviewsByTopic: async (userId: string, topicId: string) => {
    const reviewsRef = collection(db, 'users', userId, 'course_reviews');
    const q = query(reviewsRef, where('topicId', '==', topicId));

    const snapshot = await getDocs(q);

    if (snapshot.empty) return;

    const batch = writeBatch(db);
    snapshot.docs.forEach(doc => {
        batch.delete(doc.ref);
    });

    await batch.commit();
  },

  /**
   * 5. Conclui uma revisão e verifica se deve gerar a próxima (Loop Infinito)
   */
  completeReview: async (userId: string, review: CourseReview) => {
    const batch = writeBatch(db);

    // A. Atualiza o status da revisão atual
    const currentReviewRef = doc(db, 'users', userId, 'course_reviews', review.id);
    batch.update(currentReviewRef, { 
        status: 'completed',
        completedAt: Timestamp.now()
    });

    // B. Se for a última do ciclo e tiver repetição ativada, cria a próxima
    if (review.isLastOfCycle && review.repeatInterval) {
        const nextDate = new Date(); // Data base é hoje (data da conclusão)
        nextDate.setDate(nextDate.getDate() + review.repeatInterval);

        const nextDateStr = getLocalISODate(nextDate);
        const newReviewRef = doc(collection(db, 'users', userId, 'course_reviews'));

        const newReviewData: CourseReview = {
            ...review,
            id: newReviewRef.id,
            scheduledDate: nextDateStr,
            status: 'pending',
            reviewIndex: review.reviewIndex + 1,
            label: `REV. ${review.reviewIndex + 1} - ${review.repeatInterval} DIAS`,
            createdAt: Timestamp.now(),
            completedAt: undefined // Limpa o campo de conclusão
        };

        batch.set(newReviewRef, newReviewData);
    }

    await batch.commit();
  }
};

import React, { useEffect, useState } from 'react';
import { courseReviewService, CourseReview } from '../../../../services/courseReviewService';
import { useAuth } from '../../../../contexts/AuthContext';
import { AlertCircle, CalendarClock, CheckCircle2, ChevronRight } from 'lucide-react';

export function CourseReviewDashboard({ courseId, onReviewNow }: { courseId: string, onReviewNow: (topicId: string) => void }) {
    const { currentUser: user } = useAuth();
    const [reviews, setReviews] = useState<CourseReview[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchReviews = async () => {
        if (!user) return;
        try {
            const data = await courseReviewService.getPendingReviews(user.uid, courseId);
            setReviews(data);
        } catch (error) {
            console.error("Erro ao buscar revisões:", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReviews();
    }, [courseId, user]);

    const handleComplete = async (review: CourseReview) => {
        if (!user) return;
        // Atualização Otimista: Some da tela na hora em que clica
        setReviews(prev => prev.filter(r => r.id !== review.id));
        try {
            await courseReviewService.completeReview(user.uid, review);
        } catch (error) {
            console.error("Erro ao concluir revisão:", error);
            fetchReviews(); // Reverte caso dê erro no banco
        }
    };

    if (loading || reviews.length === 0) return null;

    // Garante a formatação da data baseada no fuso horário local do usuário (YYYY-MM-DD)
    const getLocalDateStr = () => {
        const offset = new Date().getTimezoneOffset() * 60000;
        const localDate = new Date(Date.now() - offset);
        return localDate.toISOString().split('T')[0];
    };
    const todayStr = getLocalDateStr();

    const overdueReviews = reviews.filter(r => r.scheduledDate < todayStr);
    const todayReviews = reviews.filter(r => r.scheduledDate === todayStr);

    if (overdueReviews.length === 0 && todayReviews.length === 0) return null;

    return (
        <div className="flex flex-col gap-3 mb-6 animate-in fade-in slide-in-from-top-4">
            {overdueReviews.length > 0 && (
                <div className="bg-red-900/10 border border-red-900/50 rounded-xl p-4 shadow-lg shadow-red-900/5">
                    <div className="flex items-center gap-2 mb-3">
                        <AlertCircle size={18} className="text-red-500" />
                        <h3 className="text-red-500 font-black uppercase text-sm">Revisões Atrasadas</h3>
                    </div>
                    <div className="flex flex-col gap-2">
                        {overdueReviews.map(review => (
                            <ReviewCard key={review.id} review={review} onReviewNow={onReviewNow} onComplete={handleComplete} isOverdue={true} />
                        ))}
                    </div>
                </div>
            )}

            {todayReviews.length > 0 && (
                <div className="bg-yellow-900/10 border border-yellow-900/50 rounded-xl p-4 shadow-lg shadow-yellow-900/5">
                    <div className="flex items-center gap-2 mb-3">
                        <CalendarClock size={18} className="text-yellow-500" />
                        <h3 className="text-yellow-500 font-black uppercase text-sm">Você possui revisões agendadas para hoje:</h3>
                    </div>
                    <div className="flex flex-col gap-2">
                        {todayReviews.map(review => (
                            <ReviewCard key={review.id} review={review} onReviewNow={onReviewNow} onComplete={handleComplete} isOverdue={false} />
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

