export function StudentCourseEdital({ courseId, focusTopicId }: { courseId: string, focusTopicId?: string | null }) {
    const { currentUser: user } = useAuth();
    const [structure, setStructure] = useState<CourseEditalStructure | null>(null);
    const [loading, setLoading] = useState(true);
    const [completedTopics, setCompletedTopics] = useState<string[]>([]);

    // Novas vars
    const [completedLessons, setCompletedLessons] = useState<string[]>([]);

    useEffect(() => {
        const loadData = async () => {
            if (!user) return;
            setLoading(true);
            try {
                const [editalData, topicsDone, lessonsDone] = await Promise.all([
                    courseService.getCourseEdital(courseId),
                    courseService.getCompletedTopics(user.uid, courseId),
                    courseService.getCompletedLessons(user.uid, courseId)
                ]);
                setStructure(editalData);
                // Garante que todos os IDs de tópicos sejam strings
                setCompletedTopics((topicsDone || []).map(String));
                setCompletedLessons(lessonsDone || []);
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        loadData();
    }, [courseId, user]);

    // Função Blindada para Marcar/Desmarcar o Tópico (Optimistic UI)
    const handleToggleTopic = (topicId: string | number) => {
        if (!user) return;
        const safeId = String(topicId);

        // setCompletedTopics com 'prev' garante que NUNCA usaremos dados obsoletos
        setCompletedTopics(prev => {
            const isAlreadyCompleted = prev.includes(safeId);
            const newStatus = !isAlreadyCompleted;

            // 1. Dispara o salvamento pro banco em segundo plano (não trava a tela)
            courseService.toggleTopicCompletion(user.uid, courseId, safeId, newStatus)
                .catch(err => console.error("Erro ao salvar progresso no banco:", err));

            // 2. Atualiza a interface instantaneamente (o Check fica verde na mesma hora)
            if (newStatus) {
                return [...prev, safeId];
            } else {
                return prev.filter(id => String(id) !== safeId);
            }
        });
    };

    if (loading) return <div className="flex justify-center p-20"><Loader2 className="animate-spin text-red-500" /></div>;

    if (!structure || !structure.disciplines || structure.disciplines.length === 0) {
        return (
            <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl">
                <BookOpen className="w-12 h-12 text-gray-600 mx-auto mb-4" />
                <p className="text-gray-500 uppercase font-bold text-sm">Edital não disponível.</p>
                <p className="text-gray-600 text-xs mt-1">O professor ainda não publicou o edital verticalizado.</p>
            </div>
        );
    }

    // --- CÁLCULO DA BARRA DE PROGRESSO GERAL ---
    const countTotalTopics = (items: any[]): number => {
        let count = 0;
        items.forEach(item => {
            count++; 
            if (item.subtopics && item.subtopics.length > 0) {
                count += countTotalTopics(item.subtopics); 
            }
        });
        return count;
    };

    const totalTopics = structure.disciplines.reduce((acc: number, disc: any) => acc + countTotalTopics(disc.topics || []), 0);
    const overallProgress = totalTopics > 0 ? Math.round((completedTopics.length / totalTopics) * 100) : 0;

    return (
        <div className="space-y-6 pb-20 animate-in fade-in">
            {/* Header / Resumo */}
            <div className="flex flex-col md:flex-row justify-between items-end gap-4 border-b border-gray-800 pb-6">
                <div>
                    <h2 className="text-2xl font-black text-white uppercase tracking-tighter">Edital Verticalizado</h2>
                    <p className="text-gray-500 text-sm font-medium mt-1">Acompanhe seu progresso tópico por tópico.</p>
                </div>

                {/* BARRA DE PROGRESSO GERAL */}
                <div className="bg-[#1a1d24] border border-gray-800 rounded-xl p-3 flex flex-col gap-1 w-full md:w-64">
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wider block">Progresso Geral</span>
                        <span className="text-sm font-black text-white">{overallProgress}%</span>
                    </div>
                    <div className="w-full bg-black rounded-full h-2 overflow-hidden border border-gray-800">
                        <div className="bg-green-500 h-full rounded-full transition-all duration-700 ease-out" style={{ width: `${overallProgress}%` }}></div>
                    </div>
                </div>
            </div>

            {/* Lista de Disciplinas */}
            <div className="space-y-4">
                {structure.disciplines.map(discipline => (
                    <StudentDisciplineAccordion 
                        key={discipline.id} 
                        discipline={discipline} 
                        courseId={courseId}
                        completedLessons={completedLessons}
                        completedTopics={completedTopics} 
                        onToggleTopic={handleToggleTopic}
                        focusTopicId={focusTopicId} // PASSANDO O ID DE FOCO PARA BAIXO
                    />
                ))}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { OnlineCourse, CourseModule, CONTEST_STATUS_LABELS } from '../../../types/course';
import { courseService } from '../../../services/courseService';
import { StudentModuleCard } from './StudentModuleCard';
import { CoursePlayer } from './player/CoursePlayer';
import { useAuth } from '../../../contexts/AuthContext';
import { AlertCircle, Calendar, CheckCircle2, Clock, Siren, LayoutList, ListTree } from 'lucide-react';
import { StudentCourseEdital } from './edital/StudentCourseEdital';
import { CourseReviewDashboard } from './reviews/CourseReviewDashboard';

interface CourseDetailsProps {
  course: OnlineCourse;
  onBack: () => void;
}

export function CourseDetails({ course, onBack }: CourseDetailsProps) {
  const { currentUser } = useAuth();

  // ESTADO DAS ABAS (NOVO) - MÓDULOS ou EDITAL
  const [activeTab, setActiveTab] = useState<'MODULES' | 'EDITAL'>('MODULES');
  const [focusTopicId, setFocusTopicId] = useState<string | null>(null);

  const [modules, setModules] = useState<CourseModule[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedModule, setSelectedModule] = useState<CourseModule | null>(null);

  // Estado do Progresso Geral
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const loadData = async () => {
        try {
            // 1. Carrega Módulos
            const modulesData = await courseService.getModules(course.id);
            setModules(modulesData);

            // 2. Calcula Progresso Geral
            if (currentUser) {
                const [completedIds, stats] = await Promise.all([
                    courseService.getCompletedLessons(currentUser.uid, course.id),
                    courseService.getCourseStats(course.id)
                ]);

                const total = stats.totalLessons;
                const completed = completedIds.length;
                const percentage = total > 0 ? Math.round((completed / total) * 100) : 0;

                setProgress(percentage);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };
    loadData();
  }, [course.id, currentUser]);

  // --- LÓGICA DO CONTADOR REGRESSIVO ---
  const getDaysUntilExam = () => {
    if (!course.examDate) return 0;
    const today = new Date();
    // Ajuste fuso: Criar data "local" ignorando hora
    const examDateStr = course.examDate + "T00:00:00"; 
    const exam = new Date(examDateStr);

    // Diferença em milissegundos
    const diffTime = exam.getTime() - today.getTime();
    // Converter para dias (arredondando para cima)
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays > 0 ? diffDays : 0;
  };

  const daysRemaining = getDaysUntilExam();

  // Handler para Navegação via Review
  const handleReviewNow = (topicId: string) => {
      setActiveTab('EDITAL');
      setFocusTopicId(topicId);
  };

  // Helper para renderizar o Card de Status
  const renderStatusCard = () => {
    if (!course.contestStatus || course.contestStatus === 'SEM_PREVISAO') return null;

    const statusConfig: any = {
        'COMISSAO_FORMADA': { color: 'blue', icon: <CheckCircle2 size={20} />, label: 'Comissão Formada' },
        'AUTORIZADO': { color: 'green', icon: <CheckCircle2 size={20} />, label: 'Concurso Autorizado!' },
        'BANCA_CONTRATADA': { color: 'yellow', icon: <AlertCircle size={20} />, label: `Banca Definida: ${course.examBoard || 'A definir'}` },
        'EDITAL_PUBLICADO': { color: 'red', icon: <Siren size={20} />, label: 'EDITAL PUBLICADO!' }
    };

    const config = statusConfig[course.contestStatus] || { color: 'gray', icon: <Clock size={20} />, label: CONTEST_STATUS_LABELS[course.contestStatus] };

    // Estilos baseados na cor
    const colors: any = {
        blue: 'bg-blue-900/20 border-blue-600/30 text-blue-400',
        green: 'bg-green-900/20 border-green-600/30 text-green-400',
        yellow: 'bg-yellow-900/20 border-yellow-600/30 text-yellow-500',
        red: 'bg-red-900/20 border-red-600/30 text-red-500',
        gray: 'bg-zinc-800 border-zinc-700 text-zinc-400'
    };

    const activeStyle = colors[config.color];

    return (
        <div className={`mt-6 p-4 rounded-xl border flex flex-col md:flex-row items-center justify-between gap-4 ${activeStyle} relative overflow-hidden group transition-all duration-500`}>

            {/* Informação do Status */}
