import { db, storage } from './firebase';
import { 
  collection, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  getDocs, 
  getDoc,
  query, 
  orderBy, 
  where,
  writeBatch,
  increment,
  setDoc,
  serverTimestamp,
  getCountFromServer,
  arrayUnion,
  arrayRemove
} from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { OnlineCourse, CourseFormData, CourseModule, CourseSubModule, CourseLesson, CourseContent } from '../types/course';
import { CourseEditalStructure } from '../types/courseEdital';

const COLLECTION_NAME = 'online_courses';
const MODULES_COLLECTION = 'course_modules';
const SUBMODULES_COLLECTION = 'course_submodules';
const LESSONS_COLLECTION = 'course_lessons';
const CONTENTS_COLLECTION = 'course_contents';
const EDITAL_COLLECTION = 'course_edital'; 

export const courseService = {
  // Helper para upload de Banner
  uploadBanner: async (file: File): Promise<string> => {
    try {
      const storageRef = ref(storage, `course_banners/${Date.now()}_${file.name}`);
      const snapshot = await uploadBytes(storageRef, file);
      return await getDownloadURL(snapshot.ref);
    } catch (error) {
      console.error("Erro upload banner:", error);
      throw error;
    }
  },

  // Criar novo curso
  createCourse: async (data: CourseFormData, bannerDesktopFile?: File, bannerMobileFile?: File): Promise<string> => {
    try {
      const finalData = { ...data };

      if (bannerDesktopFile) {
        finalData.bannerUrlDesktop = await courseService.uploadBanner(bannerDesktopFile);
      }
      if (bannerMobileFile) {
        finalData.bannerUrlMobile = await courseService.uploadBanner(bannerMobileFile);
      }

      const docRef = await addDoc(collection(db, COLLECTION_NAME), {
        ...finalData,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        active: true
      });
      return docRef.id;
    } catch (error) {
      console.error("Erro ao criar curso:", error);
      throw error;
    }
  },

  // Listar cursos
  getCourses: async (): Promise<OnlineCourse[]> => {
    try {
      const q = query(collection(db, COLLECTION_NAME), orderBy('createdAt', 'desc'));
      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as OnlineCourse));
    } catch (error) {
      console.error("Erro ao buscar cursos:", error);
      throw error;
    }
  },

  // Atualizar curso
  updateCourse: async (id: string, data: Partial<CourseFormData>, bannerDesktopFile?: File, bannerMobileFile?: File) => {
    try {
      const finalData = { ...data };

      if (bannerDesktopFile) {
        finalData.bannerUrlDesktop = await courseService.uploadBanner(bannerDesktopFile);
      }
      if (bannerMobileFile) {
        finalData.bannerUrlMobile = await courseService.uploadBanner(bannerMobileFile);
      }

      const docRef = doc(db, COLLECTION_NAME, id);
      await updateDoc(docRef, {
        ...finalData,
        updatedAt: new Date().toISOString()
      });
    } catch (error) {
      console.error("Erro ao atualizar curso:", error);
      throw error;
    }
  },

  // Excluir curso
  deleteCourse: async (id: string) => {
    try {
      await deleteDoc(doc(db, COLLECTION_NAME, id));
    } catch (error) {
      console.error("Erro ao excluir curso:", error);
      throw error;
    }
  },

  // Duplicar curso
  duplicateCourse: async (originalCourse: OnlineCourse) => {
    try {
      const newCourseData = {
        title: `${originalCourse.title} (Cópia)`,
        coverUrl: originalCourse.coverUrl,
        bannerUrlDesktop: originalCourse.bannerUrlDesktop,
        bannerUrlMobile: originalCourse.bannerUrlMobile,
        categoryId: originalCourse.categoryId,
        subcategoryId: originalCourse.subcategoryId || '',
        organization: originalCourse.organization || '',
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        active: true
      };

      const docRef = await addDoc(collection(db, COLLECTION_NAME), newCourseData);
      return docRef.id;
    } catch (error) {
      console.error("Erro ao duplicar curso:", error);
      throw error;
    }
  },

  // Upload de Capa
  uploadCover: async (file: File): Promise<string> => {
    try {
      const storageRef = ref(storage, `course_covers/${Date.now()}_${file.name}`);
      const snapshot = await uploadBytes(storageRef, file);
      const downloadURL = await getDownloadURL(snapshot.ref);
      return downloadURL;
    } catch (error) {
      console.error("Erro ao fazer upload da capa:", error);
      throw error;
    }
  },

  // --- MÓDULOS ---

  createModule: async (moduleData: Omit<CourseModule, 'id'>) => {
    try {
      const q = query(
        collection(db, MODULES_COLLECTION), 
        where('courseId', '==', moduleData.courseId),
        orderBy('order', 'desc')
      );
      const snapshot = await getDocs(q);
      const lastOrder = snapshot.docs.length > 0 ? snapshot.docs[0].data().order : 0;

      const docRef = await addDoc(collection(db, MODULES_COLLECTION), {
        ...moduleData,
        order: lastOrder + 1
      });
      return docRef.id;
    } catch (error) {
      console.error("Erro ao criar módulo:", error);
      throw error;
    }
  },

  getModules: async (courseId: string): Promise<CourseModule[]> => {
    try {
      const q = query(
        collection(db, MODULES_COLLECTION),
        where('courseId', '==', courseId),
        orderBy('order', 'asc')
      );
      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as CourseModule));
    } catch (error) {
      console.error("Erro ao buscar módulos:", error);
      throw error;
    }
  },

  updateModule: async (moduleId: string, data: Partial<CourseModule>) => {
    try {
      const docRef = doc(db, MODULES_COLLECTION, moduleId);
      await updateDoc(docRef, data);
    } catch (error) {
      console.error("Erro ao atualizar módulo:", error);
      throw error;
    }
  },

  deleteModule: async (moduleId: string) => {
    try {
      await deleteDoc(doc(db, MODULES_COLLECTION, moduleId));
    } catch (error) {
      console.error("Erro ao excluir módulo:", error);
      throw error;
    }
  },

  reorderModules: async (modules: CourseModule[]) => {
    try {
      const batch = writeBatch(db);
      modules.forEach((mod, index) => {
        const docRef = doc(db, MODULES_COLLECTION, mod.id);
        batch.update(docRef, { order: index + 1 });
      });
      await batch.commit();
    } catch (error) {
      console.error("Erro ao reordenar módulos:", error);
      throw error;
    }
  },

  // --- PASTAS (SUBMÓDULOS) ---

  createSubModule: async (data: Omit<CourseSubModule, 'id'>) => {
    try {
      const q = query(
        collection(db, SUBMODULES_COLLECTION), 
        where('moduleId', '==', data.moduleId),
        orderBy('order', 'desc')
      );
      const snapshot = await getDocs(q);
      const lastOrder = snapshot.docs.length > 0 ? snapshot.docs[0].data().order : 0;

      const docRef = await addDoc(collection(db, SUBMODULES_COLLECTION), {
        ...data,
        order: lastOrder + 1
      });
      return docRef.id;
    } catch (error) {
      console.error("Erro ao criar pasta:", error);
      throw error;
    }
  },

  getSubModules: async (moduleId: string): Promise<CourseSubModule[]> => {
    try {
      const q = query(
        collection(db, SUBMODULES_COLLECTION),
        where('moduleId', '==', moduleId),
        orderBy('order', 'asc')
      );
      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as CourseSubModule));
    } catch (error) {
      console.error("Erro ao buscar pastas:", error);
      throw error;
    }
  },

  updateSubModule: async (id: string, data: Partial<CourseSubModule>) => {
    await updateDoc(doc(db, SUBMODULES_COLLECTION, id), data);
  },

  deleteSubModule: async (id: string) => {
    await deleteDoc(doc(db, SUBMODULES_COLLECTION, id));
  },

  reorderSubModules: async (subModules: CourseSubModule[]) => {
    try {
      const batch = writeBatch(db);
      subModules.forEach((sub, index) => {
        const docRef = doc(db, SUBMODULES_COLLECTION, sub.id);
        batch.update(docRef, { order: index + 1 });
      });
      await batch.commit();
    } catch (error) {
      console.error("Erro ao reordenar pastas:", error);
      throw error;
    }
  },

  // --- AULAS ---

  createLesson: async (data: Omit<CourseLesson, 'id'>) => {
    try {
      let q;
      if (data.subModuleId) {
        q = query(
          collection(db, LESSONS_COLLECTION),
          where('moduleId', '==', data.moduleId),
          where('subModuleId', '==', data.subModuleId),
          orderBy('order', 'desc')
        );
      } else {
        q = query(
          collection(db, LESSONS_COLLECTION),
          where('moduleId', '==', data.moduleId),
          where('subModuleId', '==', null),
          orderBy('order', 'desc')
        );
      }

      const snapshot = await getDocs(q);
      const lastOrder = snapshot.docs.length > 0 ? snapshot.docs[0].data().order : 0;

      const docRef = await addDoc(collection(db, LESSONS_COLLECTION), {
        ...data,
        order: lastOrder + 1
      });
      return docRef.id;
    } catch (error) {
      console.error("Erro ao criar aula:", error);
      throw error;
    }
  },

  getLessons: async (moduleId: string): Promise<CourseLesson[]> => {
    try {
      const q = query(
        collection(db, LESSONS_COLLECTION),
        where('moduleId', '==', moduleId),
        orderBy('order', 'asc')
      );
      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as CourseLesson));
    } catch (error) {
      console.error("Erro ao buscar aulas:", error);
      throw error;
    }
  },

  updateLesson: async (id: string, data: Partial<CourseLesson>) => {
    await updateDoc(doc(db, LESSONS_COLLECTION, id), data);
  },

  deleteLesson: async (id: string) => {
    await deleteDoc(doc(db, LESSONS_COLLECTION, id));
  },

  moveLesson: async (lessonId: string, targetSubModuleId: string | null) => {
     await updateDoc(doc(db, LESSONS_COLLECTION, lessonId), {
         subModuleId: targetSubModuleId
     });
  },

  reorderLessons: async (lessons: CourseLesson[]) => {
    try {
      const batch = writeBatch(db);
      lessons.forEach((lesson, index) => {
        const docRef = doc(db, LESSONS_COLLECTION, lesson.id);
        batch.update(docRef, { order: index + 1 });
      });
      await batch.commit();
    } catch (error) {
      console.error("Erro ao reordenar aulas:", error);
      throw error;
    }
  },

  // --- CONTEÚDOS ---

  createContent: async (data: Omit<CourseContent, 'id'>) => {
    try {
      const q = query(
        collection(db, CONTENTS_COLLECTION), 
        where('lessonId', '==', data.lessonId),
        orderBy('order', 'desc')
      );
      const snapshot = await getDocs(q);
      const lastOrder = snapshot.docs.length > 0 ? snapshot.docs[0].data().order : 0;

      const docRef = await addDoc(collection(db, CONTENTS_COLLECTION), {
        ...data,
        order: lastOrder + 1
      });

      const lessonRef = doc(db, LESSONS_COLLECTION, data.lessonId);
      if (data.type === 'video') await updateDoc(lessonRef, { videoCount: increment(1) });
      else if (data.type === 'pdf') await updateDoc(lessonRef, { pdfCount: increment(1) });

      return docRef.id;
    } catch (error) {
      console.error("Erro ao criar conteúdo:", error);
      throw error;
    }
  },

  getContents: async (lessonId: string): Promise<CourseContent[]> => {
    try {
      const q = query(
        collection(db, CONTENTS_COLLECTION),
        where('lessonId', '==', lessonId),
        orderBy('order', 'asc')
      );
      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as CourseContent));
    } catch (error) {
      console.error("Erro ao buscar conteúdos:", error);
      throw error;
    }
  },

  updateContent: async (id: string, data: Partial<CourseContent>) => {
    await updateDoc(doc(db, CONTENTS_COLLECTION, id), data);
  },

  deleteContent: async (id: string) => {
    try {
      const contentRef = doc(db, CONTENTS_COLLECTION, id);
      const contentSnap = await getDoc(contentRef);

      if (contentSnap.exists()) {
        const content = contentSnap.data() as CourseContent;
        const lessonRef = doc(db, LESSONS_COLLECTION, content.lessonId);

        if (content.type === 'video') await updateDoc(lessonRef, { videoCount: increment(-1) });
        else if (content.type === 'pdf') await updateDoc(lessonRef, { pdfCount: increment(-1) });

        await deleteDoc(contentRef);
      }
    } catch (error) {
      console.error("Erro ao excluir conteúdo:", error);
      throw error;
    }
  },

  reorderContents: async (contents: CourseContent[]) => {
    try {
      const batch = writeBatch(db);
      contents.forEach((item, index) => {
        const docRef = doc(db, CONTENTS_COLLECTION, item.id);
        batch.update(docRef, { order: index + 1 });
      });
      await batch.commit();
    } catch (error) {
      console.error("Erro ao reordenar conteúdos:", error);
      throw error;
    }
  },

  uploadPDF: async (file: File): Promise<string> => {
    try {
      const storageRef = ref(storage, `course_pdfs/${Date.now()}_${file.name}`);
      const snapshot = await uploadBytes(storageRef, file);
      return await getDownloadURL(snapshot.ref);
    } catch (error) {
      console.error("Erro ao fazer upload do PDF:", error);
      throw error;
    }
  },

  // --- PROGRESSO ---

  toggleLessonCompletion: async (userId: string, courseId: string, lessonId: string, isCompleted: boolean) => {
    try {
        const docRef = doc(db, 'users', userId, 'course_progress', courseId);
        const docSnap = await getDoc(docRef);
        let completedLessons: string[] = [];

        if (docSnap.exists()) {
            completedLessons = docSnap.data().completedLessons || [];
        }

        if (isCompleted) {
            if (!completedLessons.includes(lessonId)) completedLessons.push(lessonId);
        } else {
            completedLessons = completedLessons.filter(id => id !== lessonId);
        }

        await setDoc(docRef, {
            completedLessons,
            lastUpdated: serverTimestamp()
        }, { merge: true });
        return true;
    } catch (error) {
        console.error("Erro ao salvar progresso:", error);
        throw error;
    }
  },

  getCompletedLessons: async (userId: string, courseId: string): Promise<string[]> => {
    try {
        const docRef = doc(db, 'users', userId, 'course_progress', courseId);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) return docSnap.data().completedLessons || [];
        return [];
    } catch (error) {
        return [];
    }
  },

  // --- NOVAS FUNÇÕES PARA O PROGRESSO DO EDITAL VERTICALIZADO ---

  getCompletedTopics: async (userId: string, courseId: string) => {
    try {
      // Cria um documento único para o progresso do edital do aluno neste curso
      const progressRef = doc(db, 'course_edital_progress', `${userId}_${courseId}`);
      const snap = await getDoc(progressRef);
      if (snap.exists() && snap.data().completedTopics) {
        return snap.data().completedTopics;
      }
      return [];
    } catch (error) {
      console.error("Erro ao buscar tópicos concluídos:", error);
      return [];
    }
  },

  toggleTopicCompletion: async (userId: string, courseId: string, topicId: string, isCompleted: boolean) => {
    try {
      const progressRef = doc(db, 'course_edital_progress', `${userId}_${courseId}`);

      // Usa arrayUnion para adicionar ou arrayRemove para tirar o ID do tópico
      if (isCompleted) {
        await setDoc(progressRef, { completedTopics: arrayUnion(topicId) }, { merge: true });
      } else {
        await setDoc(progressRef, { completedTopics: arrayRemove(topicId) }, { merge: true });
      }
    } catch (error) {
      console.error("Erro ao alternar conclusão do tópico:", error);
    }
  },

  getCourseStats: async (courseId: string) => {
    try {
      const modules = await courseService.getModules(courseId);
      const moduleIds = modules.map(m => m.id);
      if (moduleIds.length === 0) return { totalLessons: 0 };

      let totalLessons = 0;
      const lessonsRef = collection(db, LESSONS_COLLECTION);
      for (const modId of moduleIds) {
          const q = query(lessonsRef, where('moduleId', '==', modId));
          const snapshot = await getCountFromServer(q);
          totalLessons += snapshot.data().count;
      }
      return { totalLessons };
    } catch (error) {
      return { totalLessons: 0 };
    }
  },

  // --- EDITAL VERTICALIZADO ---

  getCourseEdital: async (courseId: string): Promise<CourseEditalStructure | null> => {
    try {
      const docRef = doc(db, EDITAL_COLLECTION, courseId);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return docSnap.data() as CourseEditalStructure;
      }
      return null;
    } catch (error) {
      return null;
    }
  },

  saveCourseEdital: async (data: CourseEditalStructure) => {
    try {
      const docRef = doc(db, EDITAL_COLLECTION, data.courseId);

      // SANITIZAÇÃO: Remove campos 'undefined' que quebram o Firestore
      // JSON.stringify ignora chaves com valor undefined
      const sanitizedData = JSON.parse(JSON.stringify(data));

      await setDoc(docRef, {
        ...sanitizedData,
        updatedAt: serverTimestamp()
      });
    } catch (error) {
      console.error("Erro ao salvar edital:", error);
      throw error;
    }
  },

  // --- NOVOS MÉTODOS PARA VINCULAÇÃO E UPLOAD DO EDITAL ---

  // Retorna estrutura completa do curso (Módulos + Pastas + Aulas) para o modal de vinculação
  getCourseStructure: async (courseId: string) => {
    try {
      // 1. Busca Módulos
      const modulesRef = collection(db, MODULES_COLLECTION);
      const qModules = query(modulesRef, where('courseId', '==', courseId), orderBy('order', 'asc'));
      const modulesSnap = await getDocs(qModules);

      const structure = [];

      // 2. Para cada módulo, busca pastas e aulas
      for (const modDoc of modulesSnap.docs) {
        const mod = { id: modDoc.id, ...modDoc.data() } as CourseModule;

        // Busca pastas (submódulos) deste módulo
        const subRef = collection(db, SUBMODULES_COLLECTION);
        const qSub = query(subRef, where('moduleId', '==', mod.id), orderBy('order', 'asc'));
        const subSnap = await getDocs(qSub);
        const subModules = subSnap.docs.map(d => ({ id: d.id, ...d.data() } as CourseSubModule));

        // Busca aulas deste módulo
        const lessonsRef = collection(db, LESSONS_COLLECTION);
        const qLessons = query(lessonsRef, where('moduleId', '==', mod.id), orderBy('order', 'asc'));
        const lessonsSnap = await getDocs(qLessons);
        const lessons = lessonsSnap.docs.map(d => ({ id: d.id, ...d.data() } as CourseLesson));

        // Monta a árvore relacional
        structure.push({
          ...mod,
          folders: subModules.map(folder => ({
            ...folder,
            // Aulas que pertencem a esta pasta
            lessons: lessons.filter(l => l.subModuleId === folder.id) 
          })),
          // Aulas que estão soltas no módulo (sem pasta)
          looseLessons: lessons.filter(l => !l.subModuleId) 
        });
      }

      return structure;
    } catch (error) {
      console.error("Erro ao buscar estrutura do curso:", error);
      return [];
    }
  },

  // Upload de Material Específico do Edital
  uploadEditalFile: async (file: File, courseId: string, topicId: string): Promise<{url: string, path: string}> => {
      try {
        const uniqueName = `${Date.now()}_${file.name}`;
        // Path organizado por curso e tópico
        const path = `courses/${courseId}/edital_pdfs/${topicId}/${uniqueName}`;
        const storageRef = ref(storage, path);

        const snapshot = await uploadBytes(storageRef, file);
        const url = await getDownloadURL(snapshot.ref);

        return { url, path };
      } catch (error) {
        console.error("Erro upload PDF edital:", error);
        throw error;
      }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { X, Save, Loader2, Upload, Image as ImageIcon } from 'lucide-react';
import { courseService } from '../../../services/courseService';
import { getCategories, Category } from '../../../services/planService';
import { OnlineCourse, CourseFormData, ContestStatus, CONTEST_STATUS_LABELS } from '../../../types/course';

interface CourseModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: CourseFormData, bannerDesktopFile?: File, bannerMobileFile?: File) => Promise<void>;
  initialData?: OnlineCourse | null;
}

export function CourseModal({ isOpen, onClose, onSave, initialData }: CourseModalProps) {
  const [formData, setFormData] = useState<CourseFormData>({
    title: '',
    description: '',
    coverUrl: '',
    categoryId: '',
    subcategoryId: '',
    organization: '',
    contestStatus: 'SEM_PREVISAO',
    examBoard: '',
    examDate: ''
  });

  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(false);

  // Estados para Upload
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Estados para Banners (Netflix Style)
  const [bannerDesktopFile, setBannerDesktopFile] = useState<File | null>(null);
  const [bannerMobileFile, setBannerMobileFile] = useState<File | null>(null);

  // Carregar categorias
  useEffect(() => {
    const loadCategories = async () => {
      try {
        const data = await getCategories();
        setCategories(data);
      } catch (error) {
        console.error("Erro ao carregar categorias", error);
      }
    };
    if (isOpen) loadCategories();
  }, [isOpen]);

  // Preencher dados na edição
  useEffect(() => {
    if (initialData) {
      setFormData({
        title: initialData.title,
        description: initialData.description || '',
        coverUrl: initialData.coverUrl,
        categoryId: initialData.categoryId,
        subcategoryId: initialData.subcategoryId || '',
        organization: initialData.organization || '',
        contestStatus: initialData.contestStatus || 'SEM_PREVISAO',
        examBoard: initialData.examBoard || '',
        examDate: initialData.examDate || '',
        bannerUrlDesktop: initialData.bannerUrlDesktop,
        bannerUrlMobile: initialData.bannerUrlMobile,
      });
      setPreviewUrl(initialData.coverUrl); // Mostra a capa atual
    } else {
      // Reset
      setFormData({ 
          title: '', 
          description: '',
          coverUrl: '', 
          categoryId: '', 
          subcategoryId: '', 
          organization: '',
          contestStatus: 'SEM_PREVISAO',
          examBoard: '',
          examDate: ''
      });
      setPreviewUrl('');
      setSelectedFile(null);
    }
    // Reset banner files on open/change
    setBannerDesktopFile(null);
    setBannerMobileFile(null);
  }, [initialData, isOpen]);

  // Handler de Seleção de Arquivo
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);

      // Cria URL temporária para preview
      const objectUrl = URL.createObjectURL(file);
      setPreviewUrl(objectUrl);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validação: Precisa ter capa (ou uma nova selecionada, ou uma já existente na URL)
    if (!formData.title || !formData.categoryId || (!selectedFile && !formData.coverUrl)) {
      alert("Preencha os campos obrigatórios e adicione uma capa.");
      return;
    }

    setLoading(true);
    try {
      let finalCoverUrl = formData.coverUrl;

      // Se houver novo arquivo, faz o upload primeiro
      if (selectedFile) {
        finalCoverUrl = await courseService.uploadCover(selectedFile);
      }

      // Prepara objeto final (limpando campos condicionais)
      const finalData = { ...formData };

      if (finalData.contestStatus !== 'BANCA_CONTRATADA') {
          delete finalData.examBoard;
      }
      if (finalData.contestStatus !== 'EDITAL_PUBLICADO') {
          delete finalData.examDate;
      }

      // Salva os dados do curso com a URL da imagem (nova ou antiga)
      // Passa os arquivos de banner para o componente pai (AdminCoursesTab -> courseService)
      await onSave({
        ...finalData,
        coverUrl: finalCoverUrl
      }, bannerDesktopFile || undefined, bannerMobileFile || undefined);

      onClose();
    } catch (error) {
      console.error(error);
      alert("Erro ao salvar curso");
    } finally {
      setLoading(false);
    }
  };

  // Helper para subcategorias
  const activeCategory = categories.find(c => c.id === formData.categoryId);
  const currentSubcategories = activeCategory ? activeCategory.subcategories : [];

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-[#121418] border border-gray-800 rounded-xl w-full max-w-2xl shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="p-6 border-b border-gray-800 flex justify-between items-center shrink-0 bg-zinc-900/50">
          <h2 className="text-xl font-bold text-white tracking-tight">
            {initialData ? 'Editar Curso' : 'Novo Curso Online'}
          </h2>
          <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Form com Scroll se necessário */}
        <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto custom-scrollbar">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Nome do Curso */}
            <div className="md:col-span-2">
                <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Nome do Curso <span className="text-red-500">*</span></label>
                <input 
                type="text" 
                value={formData.title}
                onChange={e => setFormData({...formData, title: e.target.value})}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-3 text-sm text-white focus:border-brand-red outline-none font-bold uppercase transition-colors"
                placeholder="Ex: Curso de Direito Penal Completo"
                required
                />
            </div>

            {/* Categorias */}
            <div>
              <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Categoria <span className="text-red-500">*</span></label>
              <select 
                value={formData.categoryId}
                onChange={e => setFormData({...formData, categoryId: e.target.value, subcategoryId: ''})}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-3 text-sm text-white focus:border-brand-red outline-none appearance-none cursor-pointer uppercase font-bold"
                required
              >
                <option value="">Selecione...</option>
                {categories.map(cat => (
                  <option key={cat.id} value={cat.id}>{cat.name}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Subcategoria</label>
              <select 
                value={formData.subcategoryId}
                onChange={e => setFormData({...formData, subcategoryId: e.target.value})}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-3 text-sm text-white focus:border-brand-red outline-none appearance-none cursor-pointer uppercase"
                disabled={currentSubcategories.length === 0}
              >
                <option value="">{currentSubcategories.length === 0 ? 'Sem opções' : 'Selecione...'}</option>
                {currentSubcategories.map(sub => (
                  <option key={sub} value={sub}>{sub}</option>
                ))}
              </select>
            </div>

            {/* Organização e Status */}
            <div>
                <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Órgão (Opcional)</label>
                <input 
                type="text" 
                value={formData.organization}
                onChange={e => setFormData({...formData, organization: e.target.value})}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-3 text-sm text-white focus:border-brand-red outline-none font-bold uppercase transition-colors placeholder-zinc-700"
                placeholder="Ex: Polícia Federal"
                />
            </div>

            <div>
                <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Status do Concurso</label>
                <select 
                    value={formData.contestStatus}
                    onChange={e => setFormData({...formData, contestStatus: e.target.value as ContestStatus})}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-3 text-sm text-white focus:border-brand-red outline-none cursor-pointer uppercase"
                >
                    {Object.entries(CONTEST_STATUS_LABELS).map(([key, label]) => (
                        <option key={key} value={key}>{label}</option>
                    ))}
                </select>
            </div>
          </div>

          {/* CAMPOS CONDICIONAIS DE STATUS */}
          <div className="grid grid-cols-1 gap-4 bg-[#1a1d24] p-4 rounded-lg border border-gray-800 transition-all">
             {/* Condicional: Banca Contratada */}
             {formData.contestStatus === 'BANCA_CONTRATADA' && (
                <div className="animate-in slide-in-from-top-2 fade-in">
                    <label className="block text-[10px] font-bold text-yellow-500 uppercase tracking-widest mb-1">Nome da Banca Examinadora</label>
                    <input 
                        type="text" 
                        value={formData.examBoard || ''}
                        onChange={e => setFormData({...formData, examBoard: e.target.value})}
                        className="w-full bg-black border border-gray-700 rounded-lg p-3 text-sm text-white focus:border-yellow-500 outline-none uppercase font-bold"
                        placeholder="Ex: CEBRASPE, FGV, VUNESP..."
                        autoFocus
                    />
                </div>
             )}

             {/* Condicional: Edital Publicado */}
             {formData.contestStatus === 'EDITAL_PUBLICADO' && (
                <div className="animate-in slide-in-from-top-2 fade-in">
                    <label className="block text-[10px] font-bold text-red-500 uppercase tracking-widest mb-1">Data da Prova</label>
                    <input 
                        type="date" 
                        value={formData.examDate || ''}
                        onChange={e => setFormData({...formData, examDate: e.target.value})}
                        className="w-full bg-black border border-gray-700 rounded-lg p-3 text-sm text-white focus:border-red-500 outline-none uppercase font-bold"
                        autoFocus
                    />
                    <p className="text-[9px] text-gray-500 mt-1 pl-1">
                        * Isso ativará o contador regressivo na área do aluno.
                    </p>
                </div>
             )}

             {/* Outros status apenas informativos */}
             {['SEM_PREVISAO', 'COMISSAO_FORMADA', 'AUTORIZADO'].includes(formData.contestStatus || '') && (
                 <div className="text-center text-gray-500 text-xs italic py-2">
                    O status "{CONTEST_STATUS_LABELS[formData.contestStatus as ContestStatus]}" será exibido como um aviso simples para o aluno.
                 </div>
             )}
          </div>

          {/* Descrição */}
          <div>
            <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Descrição do Curso</label>
            <textarea 
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
              className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-3 text-sm text-white focus:border-brand-red outline-none h-24 resize-none transition-colors"
              placeholder="Descreva o conteúdo do curso..."
            />
          </div>

          {/* --- UPLOAD DE CAPA --- */}
          <div>
            <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-2">Capa do Curso <span className="text-red-500">*</span></label>

            {/* Área de Visualização/Upload */}
            <div 
                onClick={() => fileInputRef.current?.click()}
                className={`
                    relative w-full aspect-[474/200] rounded-xl border-2 border-dashed 
                    flex flex-col items-center justify-center cursor-pointer overflow-hidden group transition-all
                    ${previewUrl ? 'border-brand-red/50' : 'border-zinc-700 hover:border-zinc-500 hover:bg-white/5'}
                `}
            >
                {/* Input Invisível */}
                <input 
                    type="file" 
                    ref={fileInputRef}
                    onChange={handleFileSelect}
                    accept="image/*"
                    className="hidden"
                />

                {/* Preview da Imagem */}
                {previewUrl ? (
                    <>
                        <img src={previewUrl} alt="Capa" className="w-full h-full object-cover opacity-60 group-hover:opacity-40 transition-opacity" />
                        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                            <span className="flex items-center gap-2 bg-black/80 text-white px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide">
                                <Upload size={14} /> Trocar Imagem
                            </span>
                        </div>
                    </>
                ) : (
                    <div className="text-center p-4 flex flex-col items-center gap-2">
                        <div className="p-3 bg-zinc-900 rounded-full text-zinc-500 group-hover:text-zinc-300 transition-colors">
                            <ImageIcon size={24} />
                        </div>
                        <div>
                            <p className="text-zinc-400 text-xs font-bold uppercase">Clique para enviar imagem</p>
                            <p className="text-zinc-600 text-[10px] mt-0.5">Recomendado: 474x1000px (Vertical)</p>
                        </div>
                    </div>
                )}
            </div>
          </div>

          {/* NOVA SEÇÃO: BANNERS (Estilo Netflix) */}
          <div className="border-t border-gray-800 pt-4 mt-2">
            <h3 className="text-sm font-bold text-gray-400 uppercase mb-4">Personalização Visual (Banners)</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Upload Banner Desktop */}
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Banner Horizontal (PC/TV)</label>
                    <input 
                        type="file" 
                        accept="image/*"
                        onChange={(e) => setBannerDesktopFile(e.target.files?.[0] || null)}
                        className="w-full bg-black border border-gray-800 rounded-lg p-2 text-white text-xs"
                    />
                    <p className="text-[10px] text-gray-600 mt-1">Proporção ideal: 1920x1080px (16:9)</p>
                    {formData.bannerUrlDesktop && !bannerDesktopFile && (
                         <p className="text-[10px] text-green-500 mt-1">Imagem atual já cadastrada.</p>
                    )}
                </div>

                {/* Upload Banner Mobile */}
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Banner Vertical (Celular)</label>
                    <input 
                        type="file" 
                        accept="image/*"
                        onChange={(e) => setBannerMobileFile(e.target.files?.[0] || null)}
                        className="w-full bg-black border border-gray-800 rounded-lg p-2 text-white text-xs"
                    />
                    <p className="text-[10px] text-gray-600 mt-1">Proporção ideal: 1080x1350px (4:5)</p>
                     {formData.bannerUrlMobile && !bannerMobileFile && (
                         <p className="text-[10px] text-green-500 mt-1">Imagem atual já cadastrada.</p>
                    )}
                </div>
            </div>
          </div>

        </form>

        {/* Footer */}
        <div className="p-6 pt-4 border-t border-zinc-900 bg-zinc-900/30 flex justify-end gap-3 shrink-0">
            <button 
                type="button" 
                onClick={onClose} 
                className="px-6 py-3 rounded-xl border border-zinc-800 text-zinc-400 hover:text-white hover:bg-zinc-800 font-bold uppercase text-xs tracking-widest transition-colors"
            >
              Cancelar
            </button>
            <button 
              onClick={handleSubmit} 
              disabled={loading}
              className="px-8 py-3 bg-brand-red hover:bg-red-600 text-white font-black uppercase text-xs tracking-widest rounded-xl transition-all disabled:opacity-50 shadow-lg shadow-red-900/20 flex items-center gap-2"
            >
              {loading ? (
                <>
                    <Loader2 size={16} className="animate-spin" />
                    Salvando...
                </>
              ) : 'Salvar Curso'}
            </button>
        </div>

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { courseService } from '../../../services/courseService';
import { getCategories, Category } from '../../../services/planService';
import { OnlineCourse, CourseFormData } from '../../../types/course';
import { CourseCard } from './CourseCard';
import { CourseModal } from './CourseModal';
import { CourseContentManager } from './CourseContentManager';
import ConfirmationModal from '../../ui/ConfirmationModal';
import CategoryManager from '../CategoryManager';

export function AdminCoursesTab() {
  // Estados de Dados
  const [courses, setCourses] = useState<OnlineCourse[]>([]);
  const [filteredCourses, setFilteredCourses] = useState<OnlineCourse[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);

  // Estados de Filtro
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedSubcategory, setSelectedSubcategory] = useState('');

  // Estados de Modais e Navegação
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [editingCourse, setEditingCourse] = useState<OnlineCourse | null>(null);
  const [courseToDelete, setCourseToDelete] = useState<OnlineCourse | null>(null);
  const [courseToDuplicate, setCourseToDuplicate] = useState<OnlineCourse | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Estado para Gerenciamento de Conteúdo (Navegação)
  const [managingCourse, setManagingCourse] = useState<OnlineCourse | null>(null);

  // Carregar Dados Iniciais
  const loadData = async () => {
    setLoading(true);
    try {
      const [coursesData, categoriesData] = await Promise.all([
        courseService.getCourses(),
        getCategories()
      ]);
      setCourses(coursesData);
      setCategories(categoriesData);
      setFilteredCourses(coursesData);
    } catch (error) {
      console.error("Erro ao carregar dados", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  // Lógica de Filtragem Avançada
  useEffect(() => {
    const results = courses.filter(course => {
      // 1. Filtro de Texto (Nome ou Órgão)
      const matchesSearch = 
        course.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        course.organization?.toLowerCase().includes(searchTerm.toLowerCase());

      // 2. Filtro de Categoria
      const matchesCategory = selectedCategory ? course.categoryId === selectedCategory : true;

      // 3. Filtro de Subcategoria
      const matchesSubcategory = selectedSubcategory ? course.subcategoryId === selectedSubcategory : true;

      return matchesSearch && matchesCategory && matchesSubcategory;
    });
    setFilteredCourses(results);
  }, [searchTerm, selectedCategory, selectedSubcategory, courses]);

  // Handlers CRUD
  const handleSaveCourse = async (data: CourseFormData, bannerDesktopFile?: File, bannerMobileFile?: File) => {
    if (editingCourse) {
      await courseService.updateCourse(editingCourse.id, data, bannerDesktopFile, bannerMobileFile);
    } else {
      await courseService.createCourse(data, bannerDesktopFile, bannerMobileFile);
    }
    await loadData();
    setEditingCourse(null);
  };

  const handleDeleteCourse = async () => {
    if (courseToDelete) {
      setIsProcessing(true);
      try {
        await courseService.deleteCourse(courseToDelete.id);
        await loadData();
        setCourseToDelete(null);
      } catch (error) {
         console.error(error);
      } finally {
         setIsProcessing(false);
      }
    }
  };

  const handleDuplicateCourse = async () => {
    if (courseToDuplicate) {
        setIsProcessing(true);
      try {
        await courseService.duplicateCourse(courseToDuplicate);
        await loadData();
        setCourseToDuplicate(null);
      } catch (error) {
         console.error(error);
      } finally {
        setIsProcessing(false);
      }
    }
  };

  const handleManageContent = (course: OnlineCourse) => {
    setManagingCourse(course);
  };

  // Helper para obter subcategorias da categoria selecionada
  const activeCategory = categories.find(c => c.id === selectedCategory);
  const currentSubcategories = activeCategory ? activeCategory.subcategories : [];

  // RENDERIZAÇÃO CONDICIONAL: GERENCIADOR DE CONTEÚDO
  if (managingCourse) {
    return (
      <CourseContentManager 
        course={managingCourse} 
        onBack={() => {
          setManagingCourse(null);
          loadData(); // Recarrega dados ao voltar para refletir mudanças
        }} 
      />
    );
  }

  // RENDERIZAÇÃO PADRÃO: LISTA DE CURSOS
  return (
    <div className="space-y-6 animate-in fade-in">

      {/* --- HEADER E AÇÕES --- */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-white uppercase tracking-tighter">
            CURSOS <span className="text-red-600">ONLINE</span>
          </h2>
          <p className="text-gray-400 text-sm">Gerencie suas turmas e conteúdos de videoaulas.</p>
        </div>

        <div className="flex items-center gap-3">
            {/* Botão Gerenciar Categorias */}
            <button 
                onClick={() => setIsCategoryManagerOpen(true)}
                className="px-4 py-3 bg-[#1a1d24] hover:bg-[#202329] text-gray-300 font-bold uppercase text-xs rounded border border-gray-800 transition-colors flex items-center gap-2"
            >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" /></svg>
                Gerenciar Categorias
            </button>

            {/* Botão Novo Curso */}
            <button 
                onClick={() => { setEditingCourse(null); setIsModalOpen(true); }}
                className="px-6 py-3 bg-red-600 hover:bg-red-500 text-white font-bold uppercase text-xs rounded shadow-lg shadow-red-900/20 transition-all flex items-center gap-2"
            >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                Criar Novo Curso
            </button>
        </div>
      </div>

      {/* --- BARRA DE FILTRAGEM --- */}
      <div className="bg-[#121418] p-2 rounded-xl border border-gray-800 flex flex-col md:flex-row gap-2 items-center">

        {/* Label Filtros */}
        <div className="flex items-center gap-2 px-3 text-gray-500 font-bold text-xs uppercase tracking-wider">
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>
            Filtros:
        </div>

        {/* Select Categoria */}
        <div className="relative min-w-[200px]">
            <select
                value={selectedCategory}
                onChange={(e) => {
                    setSelectedCategory(e.target.value);
                    setSelectedSubcategory(''); // Resetar subcategoria ao trocar categoria
                }}
                className="w-full bg-black border border-gray-800 rounded px-3 py-2.5 text-xs text-white focus:border-red-600 outline-none appearance-none font-medium uppercase"
            >
                <option value="">Todas as Categorias</option>
                {categories.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                ))}
            </select>
            <div className="absolute right-3 top-3 pointer-events-none text-gray-500">
                <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
            </div>
        </div>

        {/* Select Subcategoria */}
        <div className="relative min-w-[200px]">
            <select
                value={selectedSubcategory}
                onChange={(e) => setSelectedSubcategory(e.target.value)}
                disabled={!selectedCategory}
                className="w-full bg-black border border-gray-800 rounded px-3 py-2.5 text-xs text-white focus:border-red-600 outline-none appearance-none font-medium uppercase disabled:opacity-50 disabled:cursor-not-allowed"
            >
                <option value="">Todas as Subcategorias</option>
                {currentSubcategories.map(sub => (
                    <option key={sub} value={sub}>{sub}</option>
                ))}
            </select>
            <div className="absolute right-3 top-3 pointer-events-none text-gray-500">
                <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
            </div>
        </div>

        {/* Input de Pesquisa */}
        <div className="flex-1 relative w-full">
          <svg className="w-4 h-4 text-gray-500 absolute left-3 top-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <input 
            type="text" 
            placeholder="BUSCAR POR ÓRGÃO OU TÍTULO..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-black border border-gray-800 rounded pl-9 p-2.5 text-xs text-white focus:border-red-600 outline-none uppercase font-medium placeholder-gray-600"
          />
        </div>
      </div>

      {/* --- GRID DE CURSOS --- */}
      {loading ? (
        <div className="flex justify-center py-20">
           <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-red-600"></div>
        </div>
      ) : filteredCourses.length === 0 ? (
        <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl bg-gray-900/20">
          <p className="text-gray-500">Nenhum curso encontrado com os filtros atuais.</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
          {filteredCourses.map(course => (
            <CourseCard 
              key={course.id} 
              course={course} 
              onEdit={(c) => { setEditingCourse(c); setIsModalOpen(true); }}
              onManage={handleManageContent}
              onDelete={setCourseToDelete}
              onDuplicate={setCourseToDuplicate}
            />
          ))}
        </div>
      )}

      {/* --- MODAIS --- */}

      {/* Modal de Criação/Edição de Curso */}
      <CourseModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={handleSaveCourse}
        initialData={editingCourse}
      />

      {/* Modal de Gerenciamento de Categorias */}
      <CategoryManager
        isOpen={isCategoryManagerOpen}
        onClose={() => {
            setIsCategoryManagerOpen(false);
            loadData();
        }}
        categories={categories}
        refreshData={loadData}
      />

      {/* Modal de Confirmação de Exclusão */}
      <ConfirmationModal 
        isOpen={!!courseToDelete}
        title="Excluir Curso?"
        message={`Tem certeza que deseja excluir "${courseToDelete?.title}"? Esta ação não pode ser desfeita.`}
        onConfirm={handleDeleteCourse}
        onClose={() => setCourseToDelete(null)}
        variant="danger"
        isLoading={isProcessing}
      />

      {/* Modal de Confirmação de Duplicação */}
      <ConfirmationModal 
        isOpen={!!courseToDuplicate}
        title="Duplicar Curso?"
        message={`Deseja criar uma cópia de "${courseToDuplicate?.title}"?`}
        confirmText="Sim, Duplicar"
        onConfirm={handleDuplicateCourse}
        onClose={() => setCourseToDuplicate(null)}
        variant="primary"
        isLoading={isProcessing}
      />

    </div>
  );
}

